"""
Standalone patch — writes mkt-context for Isaiah 29-32.
Run: python3 scripts/zc-context-isaiah-29-32-patch.py
Chapters: 29 (24v), 30 (33v), 31 (9v), 32 (20v) = 86 verses
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISA_CONTEXT = {
  "29": {
    "1": "<p>'Woe to Ariel, to Ariel, the city where David made his camp!' — Ariel (ari'el) is a pun-name for Jerusalem carrying two senses: (1) 'lion of God' (ari = lion + el = God) = the city of royal power; and (2) 'hearth of God' (ariel = the altar hearth of the temple, Ezek 43:15-16 uses ariel for the top of the altar). Isaiah exploits both meanings: Jerusalem is both YHWH's lion-city and the altar-hearth where sacrifices are offered — and the city itself will become the sacrifice. 'The city where David made his camp' (qiryah chanah david, the city David camped) = Zion, the Jebusite city David captured in 2 Sam 5:7-9. 'Add year to year; let the festivals continue their cycle' (sefeh shanah al-shanah chaggim yingozu, add year to year, let the feasts go around) — sarcastic: continue your religious calendar uninterrupted; judgment is approaching anyway.</p>",
    "2": "<p>'Yet I will besiege Ariel; there will be mourning and lamentation, and she will become to me like an altar hearth' — YHWH becomes the besieger: 'vahasiqoti la'ariel vehayeta tagon va'aniyah vehaytah li ka'ariel, I will besiege Ariel, and she will be mourning and lamentation, and she will be to me like an altar hearth.' The city named 'altar hearth' (ariel) will become an actual altar hearth — the city itself consumed in the fire of divine judgment as a sacrifice on its own altar. The mourning and lamentation (tagon va'aniyah, grief and groaning) reverse the festival-joy of the calendar prescribed in v.1. The bitter wordplay: the city that should be the site of sacrifices offered to YHWH becomes the sacrifice.</p>",
    "3": "<p>'I will encamp against you on every side; I will besiege you with a mound and raise siege-works against you' — YHWH as the besieging army: 'vechanithi aleikh dur vestarti aleikh matsav veheqimoti aleikh metsodot, I will encamp against you as a circle, I will besiege you with a watch-post, and I will raise siege-works against you.' The 'circle' (dur = a circle, encompassing siege) = the complete surrounding of the city. The siege-mound (matsav, a raised platform for battering rams or archers) and siege-works (metsodot, siege-towers/fortifications) = standard ANE siege technology that Assyria had perfected. The theological shock: YHWH uses the same siege techniques against his own city that foreign empires use against enemy cities.</p>",
    "4": "<p>'Then you will be brought low; you will speak from the ground, and your words will come up from the dust; your voice will be like a ghost murmuring from the ground, and your speech will whisper out of the dust' — the complete humiliation of the besieged: 'veshafalt min-ha'arets tedabberi, you will be brought low, from the ground you will speak.' The Hebrew word for 'brought low' (shafalt) is the same root as the Day-of-the-LORD's bringing low the proud (2:9, 11-12, 17). Speaking 'from the ground' and 'out of the dust' = speaking as the dead speak — the defeated city's voice is reduced to a ghost-whisper. 'Like a ghost murmuring' (ke'ob, like an ob) — the ob was the familiar spirit or ghost consulted by necromancers (8:19; 1 Sam 28:7-8 = the witch of Endor's 'ob'). The city's voice reduced to the level of a spirit-consultation in the underworld.</p>",
    "5": "<p>'But the horde of your enemies will become like fine dust, and the multitude of the ruthless like blowing chaff — and in an instant, suddenly —' — the sudden reversal: 'vehayah ke'avaq dak hamon zarayikh, and the horde of your enemies will become like fine dust.' The 'fine dust' (avaq dak = fine/thin dust, the finest particles that blow away instantly) and 'blowing chaff' (kamotz over, like chaff passing away) = the harvest-threshing imagery where chaff blows away in the wind (Ps 1:4; 35:5; 83:13; Isa 17:13; 41:2). 'In an instant, suddenly' (lepeta pith'om, in an instant, suddenly) = the characteristic vocabulary of YHWH's sudden intervention (28:19: 'morning by morning it will come'; 30:13: 'suddenly, in an instant'). The dramatic three-dot pause after 'suddenly' heightens the reversal effect.</p>",
    "6": "<p>'You will be visited by the LORD of hosts with thunder and earthquake and great noise, with storm and tempest and flame of devouring fire' — the theophanic intervention: 'me'im YHWH tseva'ot tippaqed bera'am uvera'ash uvaqol gadol, from YHWH of hosts you will be visited with thunder and earthquake and great noise.' The four pairs of theophanic phenomena: thunder (ra'am), earthquake (ra'ash), great noise (qol gadol), storm (sufa), tempest (sea'rah), flame of devouring fire (lehav esh okhelah). This is the Sinai theophany vocabulary (Exod 19:16-18: thunder, lightning, thick cloud, very loud trumpet blast, smoke, fire, earthquake) applied to YHWH's eschatological intervention. YHWH the siege-engine (v.3) becomes YHWH the cosmic warrior who defeats the besiegers.</p>",
    "7": "<p>'And the multitude of all the nations that fight against Ariel — all who fight against her and her fortifications and press her hard — will be like a dream, a vision of the night' — the sudden evaporation of the nations. 'Vehayah kehalom, and it will be like a dream' (chalom = the dream that is vivid in the moment but dissolves on waking). 'Chazon layelah, a vision of the night' — the night-vision (not a prophetic vision but a sleeping dream). All the nations who muster against Zion — with their siege-mounds and battering rams — will evaporate like a dream. Ps 73:20: 'As a dream when one awakes, so when you arise, O Lord, you will despise them as fantasies.' The theological claim: imperial power, however overwhelming, is as substantial as a dream before YHWH's awakening.</p>",
    "8": "<p>'As when a hungry man dreams of eating and wakes still hungry, or as when a thirsty man dreams of drinking and wakes still parched and craving — so will the multitude of all the nations be that fight against Mount Zion' — the simile completed: 'ka'asher yachalom hara'ev vehineh okhel vehekits vereikah nafsho, as when the hungry man dreams and behold he eats but wakes and his soul is empty.' The dream-of-eating: vivid satisfaction that vanishes on waking — the dreamer wakes with the same hunger, unrelieved by the dream-meal. 'And as when the thirsty man dreams and behold he drinks but wakes and behold he is exhausted and his soul is craving' (vehadom yachalom vehineh shote vehekits vehineh ayef venafshov shoteqah). The nations' great effort against Zion = the dream-effort: they consume enormous energy in the dream (siege warfare) but achieve nothing real.</p>",
    "9": "<p>'Be stunned and bewildered; be blinded and stay blind! They are drunk, but not with wine; they stagger, but not with strong drink' — the command to be stupefied: 'hitmahmahu vatmahohu, be stunned and cause to be stunned.' The reflexive-causative form = be yourself stupefied and cause stupefaction in others. 'Be blinded' (hisha'ashu, lose control of your sight) — the total sensory disorientation. The crucial distinction: 'lo yayin shiggegah, not from wine they are drunk; lo shekhar yanu'u, not from strong drink they stagger.' The drunkenness is spiritual: the same drunkenness as the corrupt priests of 28:7, now applied more broadly. The paradox: their disorientation is YHWH's judgment on their refusal to receive his revelation (vv.11-12).</p>",
    "10": "<p>'For the LORD has poured out on you a spirit of deep sleep; he has shut your eyes — the prophets — and covered your heads — the seers' — the divine inducement of spiritual incapacity: 'ki nasakh aleikhem YHWH ruach tardema, for YHWH has poured over you a spirit of deep sleep' (tardema = the deep sleep of Gen 2:21 where YHWH caused Adam's deep sleep to form Eve; Gen 15:12 where the deep sleep came upon Abram before the covenant-cutting ceremony). The deep sleep as divine action before decisive divine activity. 'Vaye'atser et-eineikhem et-hanevi'im, he has closed your eyes — the prophets.' The seers (harozim, those who see/prophesy) have their heads covered (kisah). Paul quotes v.10 in Rom 11:8: 'God gave them a spirit of stupor, eyes that could not see and ears that could not hear, to this very day.'</p>",
    "11": "<p>'And the vision of all this has become to you like the words of a sealed book' — the inaccessibility of divine revelation: 'vattehi lakhem chazut hakol kedivre hassefer hechatumm, and the vision of all this has become to you like the words of a sealed document.' The 'sealed book' (sefer chatumm, document sealed with wax seal) = a legal document sealed and therefore inaccessible until officially opened by the authorized party. 'When someone gives it to a literate person... I cannot — it is sealed' — the literate person (yode'a sefer, one who knows a book = the scribal-educated) cannot read a sealed document, even though he has the skill. The seal must be broken by the legitimate authority. YHWH's revelation is inaccessible — not because it was not given, but because the recipients are spiritually sealed from receiving it.</p>",
    "12": "<p>'And when the book is given to one who cannot read, saying, Please read this, he answers, I cannot read' — the second scenario: the illiterate person (asher lo-yada sefer, one who does not know a book) cannot read even an unsealed book. The two cases together create a complete circle of inaccessibility: the literate cannot read because it is sealed; the illiterate cannot read because he lacks the skill. The divine word — present, given, potentially readable — is completely inaccessible to a people under the 'spirit of deep sleep.' Cf. 6:9-10: 'hearing but never understanding, seeing but never perceiving.' The same diagnostic of prophetic failure-of-reception that appears throughout Isaiah and is quoted by Jesus (Matt 13:14-15) and Paul (Acts 28:26-27; Rom 11:8).</p>",
    "13": "<p>'Because this people draw near with their mouth and honor me with their lips, while their heart is far from me, and their reverence for me is merely a commandment learned by rote from men' — the diagnosis of hollow religion. 'Ya'an ki niggash ha'am hazeh bephiv uvisfataiv kibbeduini, because this people draw near with their mouth and with their lips they honor me.' The contrast: the mouth/lips (external religious speech) vs. the heart (libbo, the seat of will, intention, and understanding). 'Their reverence for me is merely a commandment of men learned by rote' (vetihi yir'atam oti mitsvat anashim melumadah, and their fear of me is a commandment of men learned by habit/rote). The mitsvat anashim (commandment of men) vs. the mitsvot of YHWH = the religious tradition that has replaced the living covenant relationship. Jesus quotes this in Matt 15:8-9 and Mark 7:6-7, applying it to Pharisaic tradition that nullified the Torah.</p>",
    "14": "<p>'Therefore, watch — I am about to do something astonishing among this people, something astonishing and astounding; the wisdom of their wise men will perish and the insight of their discerning men will vanish' — the divine subversion of elite wisdom: 'lakhen hineni yosif lehapli et-ha'am hazeh hafle vafele, therefore I am adding to do wonders to this people, a wonder and a wonder' (hafle vafele = wonder and wonder, double emphatic for the astonishing). The 'wisdom of their wise men will perish' (veavedah chokhmah chakhamav, and the wisdom of their wise men will be lost) = the political-religious intelligentsia whose advice led to the Egypt alliance and rejection of prophetic counsel. Paul quotes v.14 in 1 Cor 1:19: 'For it is written: I will destroy the wisdom of the wise; the intelligence of the intelligent I will frustrate' — applied to the cross as the definitive 'astonishing thing' that confounds human wisdom.</p>",
    "15": "<p>'Woe to those who go to great lengths to hide their plans from the LORD, who work in darkness and say, Who sees us? Who knows us?' — the woe against concealment from YHWH: 'hoi hamme'ammikim me'YHWH lasstir etsah, woe to those who deepen from YHWH to hide their counsel' (hamme'ammikim = those who go deep = those who dig deeply to conceal). 'Who work in darkness' (uvechoshekh ma'aseihem, in darkness their deeds) — the darkness as the arena of conspiracy and political plotting. 'Who says, Who sees us? Who knows us?' (mi ro'enu umi yodenu, who sees us, who knows us?) — the rhetorical denial of divine omniscience. This is the sin of practical atheism: the political counselors who conduct their Egypt alliance negotiations without reference to YHWH because they functionally deny his oversight. Ps 94:7-9: 'They say, The Lord does not see; the God of Jacob takes no notice... Does he who formed the eye not see?'</p>",
    "16": "<p>'How you have everything backwards! Should the potter be regarded as no different from clay? Should what is made say of its maker, He did not make me? Should what is formed say of him who formed it, He has no understanding?' — the potter-clay reversal. 'Haphkhem, your turning upside-down!' (hafkham = your inversion, your complete reversal of the proper order) — not just a question but an exclamation of the absurdity. The clay (chomer) asking whether the potter (yotser, the one who forms = YHWH who 'formed' Adam in Gen 2:7) should be treated as clay = the creature treating the Creator as an equal object. 'Should what is formed say of him who formed it, He has no understanding?' (veyetser amar leyotsero lo hevin, and the formed-thing says to its former, he has no understanding) = the creature claiming intellectual superiority over the Creator. Paul uses the potter-clay in Rom 9:20-21 to address election: 'Does what is formed say to its former, Why did you make me like this?'</p>",
    "17": "<p>'Is it not just a little while until Lebanon becomes a fruitful orchard, and the fruitful orchard is considered a forest?' — the eschatological reversal of natural orders: 'halo od me'at miz'ar veshav Levanon lakkarmel, is it not a very little while, and Lebanon will turn into a fruitful field?' Lebanon (the cedar forest = the wild, unproductive but majestic forest) becomes karmel (the fruitful orchard, the cultivated productive land). Karmel (the orchard) is considered ya'ar (forest = the wild unproductive land). The reversal: the wild becomes cultivated, the cultivated is now in the category of wild. The theological application: the 'little while' (me'at miz'ar, very small from small) before the reversal of all current categories. This sets up vv.18-21: the deaf hear, the blind see, the meek rejoice — all the current 'wild' (unproductive) categories become 'cultivated' (productive).</p>",
    "18": "<p>'In that day the deaf will hear the words of a book, and out of gloom and darkness the eyes of the blind will see' — the healing of the sealed-book incapacity: 'veshamu vayom hahu hacherashim divrei sefer, and the deaf will hear in that day the words of the book.' The sealed book of v.11 (which neither literate nor illiterate could access) will be heard by the deaf. The 'words of a book' (divrei sefer = the prophetic scroll) = the revelation that was inaccessible under the spirit of deep sleep (v.10). 'And out of gloom and darkness the eyes of the blind will see' (ume'afela umichoshekh einei ivrim tir'einah, and from dimness and darkness the eyes of the blind will see). The reversal of spiritual blindness (v.10: the prophets' eyes shut). Jesus quotes this reversal in Matt 11:5 as evidence of messianic fulfillment: 'the blind receive sight, the deaf hear.'</p>",
    "19": "<p>'The meek will find renewed joy in the LORD, and the poorest among people will exult in the Holy One of Israel' — the reversal of social deprivation: 'veyasfu anavim simchah baYHWH, and the meek/humble will add joy in YHWH' (yasfu = they will add/increase joy, from yasaf = to add). The anavim (the meek/humble = the poor-and-afflicted, both economically poor and spiritually humble) are the primary beneficiaries of the eschatological reversal. 'The poorest among people' (evyone adam = the poor of humanity, the destitute in the most absolute sense) 'will exult in the Holy One of Israel' (yagilu biqedosh Yisrael, will rejoice in the Holy One of Israel). The Holy One of Israel (qedosh Yisrael) — Isaiah's distinctive divine title (25 occurrences in Isaiah vs. 6 elsewhere in OT). The meek-rejoicing echoes Ps 37:11: 'the meek will inherit the land and enjoy peace and prosperity' — Jesus quotes this in the Beatitudes (Matt 5:5).</p>",
    "20": "<p>'For the tyrant will be no more, and the scoffer will vanish, and all who look for opportunity to do wrong will be cut off' — the elimination of the oppressors: 'ki-afel arits, for the violent oppressor will be gone' (afel = gone/finished, from afes = to cease). The three categories removed: arits (the violent/ruthless, the tyrant), lets (the scoffer — the same word as the men of latson/scoffing who were Jerusalem's rulers in 28:14-22), and tsofe le'awon (those watching for evil = those who look for legal or political opportunities to harm others). The removal of these three from the eschatological community = the restoration of the covenant social order where the poor and meek are no longer preyed upon.</p>",
    "21": "<p>'Those who trap a man with a word, who lay snares for the one who rebukes corruption at the gate, and who use empty claims to deny justice to the innocent' — the three specific legal-oppression techniques of the scoffer-class: (1) 'machati adam bedavar, who make a man a sinner by a word' = legal entrapment, using a man's own words to bring false charges (cf. Matt 22:15: the Pharisees tried to 'trap him in his words'); (2) 'ulamoqesh mokhiach sha'ar, who lay a snare for the one who reproves at the gate' = targeting the judge or advocate who tries to correct corruption at the gate-court (the city gate was the legal forum: Ruth 4:1-12; Amos 5:10-12: 'they hate the one who reproves in the gate'); (3) 'vayattu vetohu tsaddiq, and turn aside with emptiness the just' = using false legal arguments to deny justice to innocent parties.</p>",
    "22": "<p>'Therefore thus says the LORD, who redeemed Abraham, concerning the house of Jacob: Jacob will no longer be ashamed; his face will no longer grow pale' — the Abraham-redemption foundation of the promise: 'lakhen ko-amar YHWH el-beit Ya'aqov asher padah et-Avraham, therefore thus says YHWH to the house of Jacob, who redeemed Abraham.' YHWH as 'the one who redeemed Abraham' (padah et-Avraham) — the call from Ur (Gen 12:1-3) as YHWH's 'redemption' of Abraham from Mesopotamian idolatry. This is the only place in the OT where YHWH is said to have 'redeemed' Abraham specifically. The foundation: if YHWH could redeem Abraham from paganism and build a nation, he can restore Jacob from shame. 'Jacob will no longer be ashamed' (lo-yevosh Ya'aqov, Jacob will not be ashamed) — the shame of national defeat and exile reversed.</p>",
    "23": "<p>'For when he sees his children — the work of my hands — in his midst, they will sanctify my name; they will sanctify the Holy One of Jacob and stand in awe of the God of Israel' — the eschatological community sanctifying YHWH: 'ki bire'oto yeladaiv ma'assei yadai beqirbo yaqdishu shemi, for when he sees his children, the work of my hands, in his midst, they will sanctify my name.' The 'children' (yeladaiv, his children = the restored community) are simultaneously 'the work of my hands' (ma'assei yadai = YHWH's own handiwork). The sanctifying of YHWH's name (yaqdishu shemi) echoes the Third Commandment and the LORD's Prayer ('hallowed be your name'). 'The Holy One of Jacob' (qedosh Ya'aqov) — a rare variant of the usual 'Holy One of Israel,' emphasizing the covenant relationship going back to the patriarch Jacob.</p>",
    "24": "<p>'Those who went astray in spirit will come to understanding, and those who complained will accept instruction' — the restoration of the spiritually wandering: 'veyade'u to'ei-ruach vinah, and those who erred in spirit will know understanding.' The to'ei-ruach (those who wandered in spirit = the spiritually disoriented, those whose inner inclination was lost) will 'know' (yade'u, from yada = the covenant-knowledge of intimate relationship). 'And those who complained will accept instruction' (verogenim yilmadu leqach, and those who murmured will learn instruction) — the rogenim (the grumblers, the same word as Israel's wilderness murmuring in Deut 1:27; Ps 106:25) will 'learn leqach' (leqach = teaching, the distilled wisdom that can be received). The full community restoration: both the spiritually wandering and the complaining resisters are brought to understanding and teachability.</p>"
  },
  "30": {
    "1": "<p>'Woe to the rebellious children, declares the LORD, who carry out plans but not mine, who make alliances but not by my Spirit, piling sin upon sin' — the Egypt-alliance woe against Hezekiah's court: 'hoi banim sorerim, woe to rebellious children' (sorerim = the stubborn/rebellious — from sarar = to be stubborn, the same root as Deut 21:18-21's 'stubborn and rebellious son' who refuses parental discipline and is brought to the elders for judgment). 'Who carry out plans but not mine' (laasos etsah velo minni, doing counsel but not from me). 'Who make alliances' (linsokh massekhah, pouring out a treaty-libation = the covenant-sealing ceremony of pouring a libation) 'but not by my Spirit' (velo ruchi = not my Spirit) — the political treaty-making done without prophetic (Spirit) consultation. 'Piling sin upon sin' (lemaan sefet chata al-chata, to add sin upon sin = the compounding of one apostasy with another).</p>",
    "2": "<p>'Who set off to go down to Egypt without asking me, who seek to find strength in Pharaoh's power and to take shelter in Egypt's shadow' — the specific failure of prophetic consultation: 'larekhet larekhed Mitsrayim uvefay lo sha'alu, who walk to go down to Egypt but my mouth they did not consult' (sha'alu = inquire/ask, the technical term for consulting YHWH through a prophet: Num 27:21; 1 Sam 28:6; 30:8). 'To find strength in Pharaoh's power' (lammoz bemo'oz Para'oh, to take refuge in Pharaoh's strength). 'To take shelter in Egypt's shadow' (velachsot betseil Mitsrayim, to take shelter in Egypt's shadow) — the 'shadow' (tsel) as protective shade echoes Num 14:9 ('their protection is gone') and Ps 121:5 ('the LORD watches over you — the LORD is your shade'). Pharaoh's shadow vs. YHWH's shadow — the misplaced security.</p>",
    "3": "<p>'Therefore the strength of Pharaoh will become your shame, and the shelter of Egypt's shadow your humiliation' — the reversal of the shelter: 'vehayah lakhem maoz Para'oh levoshet, the strength of Pharaoh will become your shame' — the very thing they sought as protection (maoz = stronghold/refuge) becomes the source of shame (boshet). 'And the shelter of Egypt's shadow your humiliation' (vehechasut betsel Mitsrayim lekhelimmah, and the shelter in Egypt's shadow becomes disgrace). The political calculation is inverted: trusting Egypt brings not security but shame. This is Isaiah's core prophetic critique: the honor-shame reversal where the high-status ally (Egypt) becomes the source of dishonor rather than the protection they sought.</p>",
    "4": "<p>'For though his officials are stationed at Zoan and his envoys have reached as far as Hanes' — the geographical detail of the Judean embassy to Egypt: 'ki-hayu besoan saraiv, for his officers/officials were at Zoan.' Zoan (Hebrew: Tsoan = Tanis/San el-Hagar in the Nile Delta) was the Egyptian capital under the 25th (Ethiopian/Kushite) Dynasty and 26th (Saite) Dynasty — the seat of Pharaoh's power and the site where diplomatic negotiations would be conducted. 'Vemalakaiv chanes yaggi'u, and his envoys reached as far as Hanes' — Hanes (possibly Herakleopolis Magna/modern Ihnasya el-Medina, further south in Middle Egypt) shows the extent of the diplomatic mission. The historical precision: real Judean embassies to real Egyptian court locations.</p>",
    "5": "<p>'Everyone will be ashamed because of a nation that cannot help them — no advantage, no aid, only shame and disgrace' — the universal shame of the Egypt policy: 'kol hevish al-am lo-yo'ilu lahem, all will be put to shame over a people who cannot benefit them.' 'No advantage' (lo le'ezer, not for help) 'no aid' (velo lemo'il, not for benefit) 'only shame and disgrace' (ki velimhah velegam cherpah, but for shame and also for reproach). The Egyptian alliance, which was designed to enhance Judah's geopolitical status, produces the precise opposite: the shame (bosheth, the public humiliation of having backed the wrong partner) and disgrace (cherpah, the reproach of a failed strategy). This is the honor-shame dynamic of ANE politics: alliance failure brought shame on both the vassal who sought the alliance and their patron who failed to deliver.</p>",
    "6": "<p>'The oracle of the beasts of the Negeb' — the Negev route oracle: 'massa behemot negev, the oracle of the beasts of the Negev/south.' This unique prophetic title introduces a description of the dangerous southern trade route to Egypt. 'Through a land of trouble and anguish, of lioness and lion, of viper and flying serpent' (be'erets tsarah vetsukah, lavi va'aryeh mimmennah, efeh vesaraf meoeph, in a land of trouble and difficulty, lioness and lion from there, viper and flying serpent) — the specific fauna of the Negev-Sinai desert corridor that caravans would traverse. The 'flying serpent' (saraf meoeph) appears in 14:29 and Num 21:6-9 (the serpents in the wilderness). 'They carry their wealth on the backs of donkeys and their treasures on the humps of camels, to a people that cannot help them' — the tribute-gift Hezekiah sent to secure Egyptian alliance (2 Kgs 18:14-16: 'Hezekiah stripped the silver from the doors of the temple and gave it all to the king of Assyria'; similar tribute to Egypt is implied).</p>",
    "7": "<p>'For Egypt's help is worthless and empty. Therefore I call her Rahab Who Sits Still' — the definitive characterization of Egypt's uselessness: 'veMitsrayim hevel varik ya'azoru, Egypt's help is emptiness and nothingness, therefore I cried for her Rahab Who Sits Still.' 'Hevel varik' (emptiness and nothingness — hevel = vanity/breath/vapor, the key word of Ecclesiastes; varik = empty/worthless) = the most dismissive possible description of Egypt's military power. 'Rahab Who Sits Still' (Rahab hem shevet) — Rahab is the ANE chaos-dragon/sea-monster (Job 9:13: 'God does not restrain his anger; even the cohorts of Rahab cowered beneath him'; 26:12; Ps 87:4: 'I will record Rahab and Babylon among those who acknowledge me'). The chaos-dragon of mythology — applied as a mocking nickname to Egypt = the monster who can't even get up, who just sits there. The nickname exposes Egypt's imperial pretension: a mythological monster who is actually paralyzed.</p>",
    "8": "<p>'Now go, write it before them on a tablet and inscribe it in a book, that it may serve as a witness for the days to come, forever and ever' — the witnessing commission: 'attah bo ketevah al-luach itam, now come, write it on a tablet with them.' Writing the oracle on a tablet (luach = a stone or wooden tablet) 'and in a book inscribe it' (ve'al sefer chuqequah, and on a scroll engrave it). The double inscription: tablet (public, permanent) and book (preserved, portable). 'Vattehi leyom acharon la'ad ad-olam, that it may be for the latter day, for ever and ever' — the prophetic testimony preserved as a legal witness against the generation that rejected it (cf. Deut 31:19: 'write down this song and teach it to the Israelites... it will be a witness for me against them'). Isaiah 8:16-17 contains the same sealing-of-testimony motif.</p>",
    "9": "<p>'For this is a rebellious people, deceptive children — children who refuse to hear the instruction of the LORD' — the covenant-violation diagnosis: 'ki am meri hu, for it is a rebellious people' (am meri, a people of rebellion — meri = obstinate rebellion, from marah = to be contentious/rebellious against authority, the same root as the name Meribah/Massah in the wilderness). 'Banim kechashim, deceptive children' (banim = children of the covenant; kechashim = those who lie/fail, from kachash = to deny/prove false). 'Lo avu shmoa torat YHWH, who refuse to hear the instruction of YHWH' — the willful refusal of Torah (torat YHWH, the instruction/law of YHWH). The parent-child rebellion language (banim sorerim in v.1; banim kechashim here) = the covenant relationship described through the family metaphor, with YHWH as the parent whose children are rebellious.</p>",
    "10": "<p>'Who say to the seers, Stop seeing, and to the prophets, Don't prophesy truth to us — speak flattering things, prophesy delusions' — the demand for comfortable prophecy: 'la'asher amru laro'im lo tir'u, who say to the seers: do not see.' The ro'im (seers = the older title for prophets, 1 Sam 9:9: 'the one now called a prophet was formerly called a seer'). 'And to the prophets: do not prophesy to us truths' (valanevim, lo tenevu lanu nesharot, to the prophets: do not prophesy straight/right things). 'Speak flattering things' (divru lanu chalaqot, speak smooth/slippery things to us) — chalaqot = the smooth, flattering speech that goes down easily (Prov 5:3: 'the lips of the adulteress drip honey'). 'Prophesy delusions' (chitzu machazot, prophesy illusions/deceptions). The demand for false prophecy has a long ANE parallel: court prophets who prophesy what kings want to hear (1 Kgs 22:6-23: Ahab's 400 prophets vs. Micaiah).</p>",
    "11": "<p>'Get out of the road, turn aside from the path; let us hear no more from the Holy One of Israel' — the radical rejection of prophetic ministry: 'suru min-haderekh, turn out of the way.' The 'way' (derekh) is the prophetic path of Torah-instruction. 'Turn aside from the path' (hattu min-hanaytiv, turn aside from the path/trodden-road). 'Let us hear no more from the Holy One of Israel' (chadilu mippaneinu qedosh Yisrael, cease from before us the Holy One of Israel) — the explicit rejection of YHWH's distinctive prophetic identity: qedosh Yisrael (the Holy One of Israel) appears 25 times in Isaiah and is virtually his prophetic signature. The people demand that this God cease to speak — they want a prophet without a Holy One of Israel behind him.</p>",
    "12": "<p>'Therefore thus says the Holy One of Israel: Because you reject this word and place your trust in oppression and cunning and rely on them' — the judicial 'therefore' after the rejection of prophetic counsel: 'lakhen ko-amar qedosh Yisrael, therefore thus says the Holy One of Israel' — the divine judge pronounces sentence. 'Ya'an ma'askhem et-haddavar hazeh, because you rejected this word.' 'And placed your trust in oppression' (vattevetchu be'oshqe, and you trusted in oppression/exploitation = the political manipulation and exploitation of the weak that characterized the court's policy). 'And cunning' (uvenalutz, and in deviance/twistedness = the diplomatic twisting/scheming of the Egypt alliance). The double trust (betach = deep reliance, the technical covenant-trust word used for misplaced confidence) — they trusted oppression and cunning instead of YHWH.</p>",
    "13": "<p>'Therefore this sin will be for you like a crack in a high wall, bulging out, about to collapse — whose fall comes suddenly, in an instant' — the crumbling-wall simile: 'vihyeh lakhem haavon hazeh kepherets nopel, and this iniquity will be for you like a falling breach.' 'Naspeh begadah shomah, bulging out in a high wall' (naspeh from saphah = puffed out/swelling; gadah = the high/towering wall). The bulging crack in the high wall: the imperceptible initial damage that suddenly becomes catastrophic collapse. 'Asher pith'om lefeta yavo shibrah, whose shattering comes suddenly, in an instant' — the same 'suddenly, in an instant' (pith'om lefeta, cf. 29:5: 'in an instant, suddenly') of divine judgment. The timing of structural failure: the crack forms slowly and invisibly, the collapse comes without warning. The Egypt alliance is that crack.</p>",
    "14": "<p>'It will shatter like a potter's vessel smashed beyond all saving — no fragment left large enough to carry a coal from the fire or scoop water from a cistern' — the total destruction of the potter's vessel: 'ushevira keshiver nevel yotsrim, and its breaking will be like the breaking of a potter's vessel shattered.' The nevel (jug/wine-jar) — a clay vessel whose shattering leaves no usable fragment. 'Lashmutz lo yachmal, he will not spare in its crushing' (lachmus, for compassion/sparing). 'Velo yimmatse vishshevatah, and in its fragments will not be found.' The standard of utter destruction: 'A coal from the fire' (gachalat esh) and 'water from a cistern' (mayim migeve) — the two basic survival tools (fire for warmth/cooking, water for drinking). Even these minimal-survival fragments are absent. Jer 19:1-11 uses the same shattered-potter's-vessel imagery for Jerusalem.</p>",
    "15": "<p>'For thus said the Lord GOD, the Holy One of Israel: In repentance and rest you shall be saved; in quietness and in trust shall be your strength. But you were not willing' — the great text of prophetic soteriology: 'bishuva venachat tivvaashe'un, in repentance/returning and rest you shall be saved.' The shuvah (returning = repentance, the turning of the covenant-breaker back to YHWH; Jer 3:12-14: 'Return, faithless Israel') and nachah (the rest/quiet of ceasing from military activity = demobilization, trusting YHWH rather than armies). 'In quietness and trust shall be your strength' (beshaqat uvetivtacha tihyeh gevuratkhem, in quietness and in trust shall be your strength) — the gerurah (strength/might) comes from the attitude of quiet trust (betach), not from military power. 'But you were not willing' (velo avitem, but you refused) — the short devastating conclusion. The invitation refused, the salvation not received.</p>",
    "16": "<p>'And you said, No! We will escape on horses — and so you will flee! We will ride on swift horses — and so those who pursue you will be swift!' — the ironic wordplay of the military rejection: 'vattemru lo ki al-sus nanus, and you said, No! For on a horse we will flee.' The cavalry strategy: 'We will escape/flee' (nanus) — the word for military retreat also means 'escape' — the cavalry is for fleeing from danger. 'Al-qal nirkav, on swift horses we will ride' — the emphasis on speed (qal = swift/light). The ironic reversal: 'therefore swift will be your pursuer' (lakhen yiqallu rodeikhem, therefore your pursuers will be swift). The speed they trust (the fast horse) is matched by faster pursuit. The faster you are, the faster your enemy will need to be — and YHWH gives the enemy the needed speed.</p>",
    "17": "<p>'A thousand will flee at the threat of one; at the threat of five you will all run, until you are left like a flagstaff on a mountaintop, like a signal flag on a hill' — the covenant-curse ratio of defeat: 'alep echad mipenei ge'arat echad, a thousand will flee at the threat of one.' Lev 26:8 reverses this for blessing: 'five of you will chase a hundred, and a hundred will chase ten thousand' — the blessing of military power multiplies the few against the many. Here the curse-ratio inverts it: the many flee from the few. 'Until you are left like a flagstaff on a mountaintop' (ad-im nothartem katorren al-rosh hahar, until you are left like a mast on the top of the mountain) — the lone flagpole (niqreh in v.17, torenm = ship's mast/flagpole) standing on an empty mountaintop: the last survivor of the army, alone and exposed, serving only as a landmark.</p>",
    "18": "<p>'Therefore the LORD waits to be gracious to you, and therefore he rises up to show you mercy. For the LORD is a God of justice; blessed are all who wait for him' — the pivot from judgment to grace: 'velakhen yechakkeh YHWH lachannenkhem, and therefore YHWH waits to be gracious to you.' The divine waiting (yechakkeh, from chakah = to wait/long for) mirrors the human waiting commanded throughout Isaiah. YHWH himself waits for the opportune moment to show grace — the waiting is not absence but readiness. 'He rises up to show you mercy' (veyarum lerachamekhem, and he rises to have compassion on you). 'For YHWH is a God of justice' (ki-elohei mishpat YHWH, for a God of justice is YHWH) — the justice (mishpat) that requires the exile also requires the restoration when the exile is complete. 'Blessed are all who wait for him' (ashre kol-chokhei lo) = the beatitude of the waiting community (Ps 37:9: 'those who wait for the LORD will inherit the land').</p>",
    "19": "<p>'For the people of Zion who dwell in Jerusalem — you will weep no more. He will surely be gracious to you at the sound of your cry; as soon as he hears it, he will answer you' — the specific promise to the Zion community: 'ki-am beTsiyon yoshev biYerushalayim, for the people of Zion, the one dwelling in Jerusalem.' The promise: 'lo-tivkeh bakho, you will weep no more — weeping you will not weep' (the emphatic absolute infinitive bako = weeping, weep). The instant responsiveness: 'channon yechannekha leqol za'aqekha, he will surely be gracious to you at the sound of your cry' (za'aqekha = your outcry, the cry of distress that YHWH heard from Egypt in Exod 3:7: 'I have heard the cry of my people'). 'As soon as he hears it, he will answer you' (keshomeo anekha, when he hears, he will answer you) — the immediacy of divine response to genuine prayer.</p>",
    "20": "<p>'And though the Lord gives you the bread of adversity and the water of affliction, your Teacher will no longer hide himself, but your eyes will see your Teacher' — the paradox of the teaching-in-affliction: 'veten lakhem adonay lechem tsar umayim lachats, and the Lord gives you bread of adversity and water of oppression.' The bread (lechem) and water (mayim) of adversity/affliction = the reduced rations of siege conditions (cf. 1 Kgs 22:27: 'Feed this man nothing but bread and water until I return safely' — prison rations). Even in these reduced conditions: 'your Teacher will no longer hide himself' (velo-yikkannef od moreka, and your Teacher will no longer hide himself). The Moreh (Teacher = from yarah, to teach; same root as Torah) who had been concealed (the sealed book, the spirit of deep sleep of 29:10-12) now appears. 'Your eyes will see your Teacher' — the direct vision of the divine instructor in the age of fulfillment.</p>",
    "21": "<p>'And your ears will hear a voice behind you saying, This is the way; walk in it, whether you turn to the right or to the left' — the guiding voice of the Teacher: 've'azneikha tishmena davar me'acharekha, and your ears will hear a word behind you saying.' The 'voice behind' (me'acharekha = from behind you) suggests the shepherd guiding the flock from behind (cf. Gen 32:7 where Jacob puts servants, flocks, and herds ahead of him; the shepherd driving from behind). 'This is the way; walk in it' (zeh haderekh, lekhu-vo, this is the way, walk in it) — the specific directional instruction for each moment of decision (whether turning right or left). The derekh (way/road) as the covenant path (Ps 16:11: 'you make known to me the path of life'; Prov 3:6: 'in all your ways acknowledge him and he will make your paths straight'). John 14:6 echoes this in Jesus's 'I am the way.'</p>",
    "22": "<p>'Then you will treat as defiled the silver coating of your carved idols and the gold plating of your cast images; you will throw them away like a menstrual rag, saying to them, Away with you!' — the spontaneous idol-rejection of the restored community: 'vetimme'tem et-tsippui pesele kaspekhm, and you will defile the plating of your silver carved idols.' The timmei (defiling) = treating as unclean (tamei, the ritual-impurity vocabulary). The gold-and-silver coated wooden idols were precious objects — the spontaneous rejection ('Away with you!' = tse = go out!) signals a fundamental change in the community's orientation. 'Like a menstrual rag' (kemo davah, like a menstruant = the most unclean object in the purity system, Lev 15:19-30) — the precious idol becomes as repugnant as the most defiling object imaginable. The same idol-rejection as 2:20; 17:7-8; 31:7.</p>",
    "23": "<p>'He will send rain for the seed you sow in the ground; the bread from the ground will be rich and plentiful. In that day your livestock will graze in spacious pastures' — the agricultural blessing of covenant restoration: 'venatan geshem zar'akha asher tizra, and he will give rain for your seed which you sow.' Rain for the seed = the fundamental blessing of Lev 26:4 ('I will send you rain in its season, and the ground will yield its crops') and Deut 28:12 ('the LORD will open the heavens... to send rain on your land in season'). The land blessing reverses the covenant curse: Deut 28:23-24 ('the sky over your head will be bronze, the ground beneath you iron; the LORD will turn the rain of your country into dust and powder'). 'Rich and plentiful bread' (lechem tenuva ha'adamah veshamen vedashemn, bread, the produce of the ground, rich and fat). 'Spacious pastures' (karkareh rachavah, a wide meadow) for the livestock.</p>",
    "24": "<p>'The oxen and donkeys that work the ground will eat salted fodder, which has been winnowed clean with shovel and fork' — the agricultural prosperity extending to working animals: 'haalapim vehacharim ovede ha'adamah belil chamits yochelu, the oxen and donkeys that work the ground will eat salted/fermented fodder.' The working animals (oxen for plowing and threshing; donkeys for transport) — the lowest tier of the agricultural system — receive special care in the restoration. 'Belil chamits' (fermented/salted fodder) = the high-quality feed of grain treated with salt or vinegar fermentation, better than plain dried grass. 'Winnowed clean with shovel and fork' (zureh bera'shan uvamizreh) = carefully processed fodder, not the rough unprocessed kind. The attention to the quality of the working animals' food signals the completeness of the blessing: even the animals eat well.</p>",
    "25": "<p>'And on every high mountain and every lofty hill there will be streams and flowing channels, on the day of the great slaughter when the towers fall' — the water-blessing on the heights: 'vehayah al-kol-har gavoah ve'al kol-giv'ah nissa yihyu pelagim yevlei mayim, and on every high mountain and every lofty hill there will be streams and channels of water.' In the dry climate of the Levant, water flows in valleys (wadis) not on mountaintops — streams on every high mountain = a miraculous super-abundance of water reversing geography. This is the new-creation imagery of water in unexpected places (cf. 35:6-7: 'water will gush in the wilderness; streams in the desert'). 'In the day of the great slaughter when the towers fall' — the military defeat of the enemy (Assyrian towers) is simultaneous with the agricultural blessing for the covenant community.</p>",
    "26": "<p>'Moreover the light of the moon will be like the light of the sun, and the light of the sun will be seven times stronger — as bright as seven days — in the day when the LORD binds up the wound of his people and heals the blow he has struck them' — the amplified luminaries of the new age: 'vehayah or halevana keor hachammah, and the light of the moon will be like the light of the sun' — the moon, which gives reflected light approximately one-millionth of the sun's brightness, will shine as brightly as the current sun. 'And the light of the sun will be sevenfold, like the light of seven days' (veor hachammah yihyeh shiv'atayim keor shiv'at hayamim, the light of the sun will be seven times, like the light of seven days). Seven = completeness; seven days = the full creation-week. Rev 21:23 and 22:5 fulfill this: 'the city does not need the sun or moon, for the glory of God gives it light.' 'When YHWH binds up the wound of his people' — the healing alongside the amplified light.</p>",
    "27": "<p>'See, the name of the LORD comes from far away, burning with anger and heavy with rising smoke; his lips are filled with fury and his tongue is like a consuming fire' — the theophanic approach of YHWH from afar: 'hineh shem YHWH ba mimerachok, behold the name of YHWH is coming from far away.' 'The name of YHWH' = YHWH himself, his self-disclosure and presence (the name as the person in ANE thought: to invoke the name is to invoke the person). 'Comes from far away' (mimerachok) — the divine warrior approaching from his heavenly dwelling (Hab 3:3: 'God came from Teman, the Holy One from Mount Paran; his glory covered the heavens'). The four theophanic features: burning anger (choleh apo, his anger burning), heavy smoke (vekoved massa, heavy with the burden of smoke), lips filled with fury (ume'lei za'am sefataiv), tongue like consuming fire (veleshono ke'esh okheleth, his tongue like eating fire).</p>",
    "28": "<p>'His breath is like a flooding stream reaching to the neck, to sift the nations through a sieve of destruction, and to put a misleading bridle on the jaws of the peoples' — the divine breath as the agent of judgment: 'verucho keanahal shotef, his breath/spirit is like a flooding stream' (shotef = the overwhelming/overflowing — the same Assyrian-flood imagery of 8:7-8; 10:22; 28:15-18 now applied to YHWH's own breath). 'Ad-tsavar, reaching to the neck' = the Assyrian flood reaching to the neck (8:8: 'it will overflow all its channels, sweeping into Judah, swirling over it, reaching up to the neck'). 'To sift the nations with a sieve of destruction' (lehanafat goyim benifat shav, to sift nations with a sieve of destruction/futility) — the nations sifted like grain through a sieve, removing the chaff. 'And a misleading bridle on the jaws of the peoples' (verimasekhet meviyah al-lechi ammim) = a bit/bridle in the mouths of the nations that causes them to go where YHWH intends, not where they plan.</p>",
    "29": "<p>'You will have a song, like the song sung at night when a holy feast is kept, and gladness of heart, like one who marches to the sound of a flute to go up to the mountain of the LORD, to the Rock of Israel' — the night-festival song of the pilgrimage community: 'hashir yihyeh lakhem keleyl hitqaddesh chag, the song will be yours like the night of the sanctification of a feast.' The night-song = the Passover night (Exod 12:42: 'a night of watching for the LORD'), when the entire celebration begins at night. 'Gladness of heart like one who marches to the sound of a flute to go up to the mountain of YHWH' (simchat lev kaholek bechalil, the gladness of heart like walking with a flute) — the joyful pilgrimage procession to the temple (Ps 42:4: 'how I used to go with the multitude, leading the procession to the house of God, with shouts of joy and praise'). 'The Rock of Israel' (tsur Yisrael) = YHWH as Rock (26:4; 2 Sam 23:3).</p>",
    "30": "<p>'The LORD will make his majestic voice heard and make visible the descent of his arm in raging anger and in the flame of a consuming fire — a cloudburst, storm, and hailstones' — the audible and visible theophany: 'vehishmia YHWH et-hod qolo, and YHWH will make heard the majesty of his voice.' The hod (majesty/thunder = the royal splendor of YHWH's voice, Ps 29:4: 'the voice of the LORD is powerful; the voice of the LORD is majestic'). 'And the descent of his arm' (venahath zero'o yar'eh, and the descent of his arm he will show) — the arm (zero'a) as the instrument of power (Exod 6:6: 'with an outstretched arm I will bring you out from Egypt'). The four weather-phenomena of the theophany: za'am (indignation/fury) + lehav esh okhelah (flame of consuming fire) + negeph (a cloudburst/plague) + zu'ah (storm/tempest) + even barad (hailstone).</p>",
    "31": "<p>'For at the voice of the LORD the Assyrian will be shattered; with his rod he will strike him down' — the specific prediction of Assyrian defeat by divine voice: 'ki-miqol YHWH yechat Ashshur, for at the voice of YHWH Assyria will be shattered.' The 'voice of YHWH' (qol YHWH) as the weapon that destroys Assyria — no human army needed. The fulfillment: 2 Kgs 19:35/Isa 37:36: 'the angel of the LORD went out and put to death 185,000 Assyrian soldiers.' 'With his rod he will strike him down' (beshebet yakkeh, with a rod/scepter he will strike) — the same shebet (rod) that YHWH used to punish Israel through Assyria (10:5: 'the rod of my anger, the staff in whose hand is my wrath') is now used against Assyria itself. The divine rod that punishes is sovereign and can be redirected against the punishing agent.</p>",
    "32": "<p>'And every blow of the rod of punishment that the LORD lays on him will be accompanied by tambourines and lyres; and with brandished arm he will battle against them' — the celebratory defeat: 'vehayah kol-maavar matteh musdah asher yaniyach YHWH alaw betupim uvekhinnorot, and it will be that every blow of the ordained rod which YHWH lays on it is with tambourines and lyres.' The matteh musdah (the rod of the founding/ordaining = the rod that has been established/appointed for this purpose) — the divine appointment of the instrument of punishment. The tambourines (tupim) and lyres (kinnorot) accompanying each blow = the instruments of the victory celebration (Exod 15:20: Miriam's tambourine after the Exodus; Ps 149:3: 'praise him with tambourine and dancing'). Each blow of divine judgment on Assyria is simultaneously a beat in the celebration-music of the redeemed.</p>",
    "33": "<p>'For Topheth has long been prepared; indeed, it is made ready for the king. Its pyre is deep and wide, with fire and wood in abundance; the breath of the LORD kindles it like a stream of burning sulfur' — the Topheth-prepared oracle: 'ki-aruch mete'mol Topheth, for Topheth has long been arranged.' Topheth (the Tophet/Topheth = from taphat = fireplace/hearth; or possibly from the Hebrew word for 'drum' = toph, used to drown out the cries of children sacrificed there) was the cultic site in the Valley of Ben Hinnom (ge-hinnom = Gehenna) south of Jerusalem where Israel burned children as offerings to Molech (Jer 7:31-32; 19:5-6; 32:35; 2 Kgs 23:10). YHWH has prepared Topheth — traditionally the site of pagan sacrifice — for the Assyrian king (hammelek, the king). 'The breath of YHWH kindles it like a stream of burning sulfur' (nishmat YHWH ke'nahal gofrit bo'eret bah, the breath of YHWH like a stream of burning sulfur kindles it) — the divine breath (v.28) now the fuel of the Assyrian king's burning in the Gehenna-site.</p>"
  },
  "31": {
    "1": "<p>'Woe to those who go down to Egypt for help, relying on horses and trusting in chariots because there are so many and in cavalry because it is so strong — but who do not look to the Holy One of Israel or seek the LORD' — the parallel woe to ch.30 against the Egypt alliance, now with explicit military-force analysis: 'hoi hayordim Mitsrayim le'ezra, woe to those going down to Egypt for help.' The military inventory: horses (sus, cavalry mounts), chariots (rekev, the 2-wheeled war machine that Egypt excelled in building — in the Battle of Kadesh/1274 BCE Egypt deployed thousands of chariots), cavalry/horsemen (parashim, the mounted riders). The contrast: 'veal-qedosh Yisrael lo shau, but they do not look to the Holy One of Israel' (shau from shaah = to look to, gaze upon) 'and the LORD they did not seek' (ve'et-YHWH lo darash, YHWH they did not consult = no prophetic inquiry, no priestly Urim and Thummim consultation).</p>",
    "2": "<p>'Yet he too is wise and brings disaster; he does not take back his word. He will arise against the house of those who do evil and against the help of those who practice wickedness' — YHWH's wisdom superior to the political counselors: 'vegam-hu chakham vayave ra, and he also is wise and brings evil/disaster.' The 'he also is wise' (gam-hu chakham) is emphatic: the counselors who devised the Egypt strategy thought they were the wise ones — YHWH is also wise, and wiser. 'He does not take back his word' (velo hesir devaraiv, and his words he has not turned aside) = the prophetic word of judgment will not be recalled. 'He will arise against the house of those who do evil' (vaqam al-beit mere'im, and he will rise against the house of the evil-doers) and 'against the help of those who practice wickedness' (ve'al ezrat po'alei aven, against the help of those who work trouble/iniquity). Both the Judean court and the Egyptian ally are YHWH's targets.</p>",
    "3": "<p>'The Egyptians are human, not God; their horses are flesh, not spirit. When the LORD stretches out his hand, the helper will stumble and the one being helped will fall, and they will all perish together' — the flesh/spirit anthropological contrast: 'veMitsrayim adam velo-el, and Egypt is a human being and not God.' The adam ('human being' from the earth, the mortal creature of Gen 2:7) vs. el (God, the eternal power). 'Their horses are flesh and not spirit' (vesuseihem basar velo-ruach, their horses are flesh and not spirit) — the basar (flesh = the frail, mortal, perishable substance) vs. ruach (spirit = the divine energy that gives life, Gen 2:7: 'breathed into his nostrils the breath of life'; 6:3: 'my Spirit will not contend with humans forever, for they are mortal'). The flesh/spirit distinction that runs through Isaiah (31:3; 40:6-7) becomes the Pauline theology of flesh vs. spirit (Rom 8:1-17; Gal 5:16-25). 'When YHWH stretches out his hand' (uvatas YHWH yado, and YHWH stretches out his hand) = Exodus language (Exod 3:20; 7:5; 9:15).</p>",
    "4": "<p>'For this is what the LORD said to me: As a lion or a young lion growls over its prey, and though a whole company of shepherds is mustered against it, it is not frightened by their shouts or intimidated by the noise — so the LORD of hosts will come down to wage war on Mount Zion and on its hill' — the protective lion of Zion: 'ka'asher yehaggeh ha'aryeh vekhafir al-terfo, as the lion roars and the young lion over its prey' (haggeh = to growl/murmur over prey — the lion crouching over its kill and growling a warning). 'A whole company of shepherds is mustered against it' (yeqqare alaw melo ro'im, a fullness of shepherds is called against him) but the lion is 'not frightened' (lo-yechat) and 'not subdued' (lo-yishpal). The paradox: YHWH 'will come down to wage war ON Mount Zion' — coming down to fight at Zion's location, but as its defender, as the lion defending its prey (Jerusalem) from the shepherds (Assyrian commanders) trying to drive it away.</p>",
    "5": "<p>'Like birds hovering over their young, so the LORD of hosts will shield Jerusalem; shielding, he will deliver it; passing over, he will rescue it' — the mother-bird protection and the Passover echo: 'ketsipporim afot ken yagen YHWH tseva'ot al-Yerushalayim, like birds hovering so YHWH of hosts will shield Jerusalem.' The tsipporim afot (birds hovering/flying over their nestlings) = the protective mother-bird imagery of Deut 32:11: 'like an eagle that stirs up its nest and hovers over its young, that spreads its wings to catch them and carries them aloft.' Ps 91:4: 'He will cover you with his feathers and under his wings you will find refuge.' 'Passing over' (pesach) — the verb is unmistakably the Passover verb (Exod 12:12-13, 23, 27: YHWH 'passed over' the houses of Israel in Egypt). Isaiah deliberately invokes Passover: the angel of destruction 'passed over' Israel; YHWH now 'passes over' Jerusalem, rescuing it from Assyria as he rescued Israel from Egypt.</p>",
    "6": "<p>'Turn back to him from whom the people of Israel have so deeply defected' — the repentance call: 'shuvu livne Yisrael lasher amqu sara, return, O sons of Israel, to him from whom you have deeply defected.' The shuvu (turn/return = the repentance of 30:15: 'in returning you shall be saved') combined with the magnitude of the departure: 'amqu sara, have deeply defected' (amaq = to go deep; sara = to turn aside/revolt; amqu sara = have gone very deep in apostasy). The deepness of the apostasy is matched by the depth of the invitation to return. The 'from whom' (asher amqu sara, from whom they deeply defected) = YHWH — the one they turned from deeply is the one they are invited to turn back to.</p>",
    "7": "<p>'For in that day every person will throw away the idols of silver and gold that their own hands have made — things that have been their sin' — the idol-rejection in the day of YHWH: 'ki vayom hahu yim'asun ish eliley kaspo ve'eliley zahavo, for in that day each man will reject his silver idols and his gold idols.' The 'that their own hands have made' (asher asu lakhem yedeikhem chet, which your own hands made for you as sin) — the idols are the product of human hands (yad = hand, the same hand that made them can throw them away). 'Things that have been your sin' (chet = sin — the idols are themselves the embodiment of the sin, not merely its occasion). The same idol-rejection as 2:20 ('on that day people will throw away to the moles and bats their idols of silver and idols of gold') and 30:22 ('you will throw them away like a menstrual rag').</p>",
    "8": "<p>'Then the Assyrian will fall by a sword that is not of any man; no human sword will consume him. He will flee from the sword, and his young warriors will be broken into forced labor' — the non-human sword of Assyrian defeat: 'venafal Ashshur becharev lo-ish, and Assyria will fall by a sword not of a man' (lo-ish = not of a man = not a human weapon). The emphatic point: Assyria's defeat will not be by human military action. 'Vecharev lo-adam tokkelenu, no sword of a human being will consume him' — two synonyms (lo-ish, lo-adam) both denying the human agency in Assyria's defeat. The fulfillment: 2 Kgs 19:35/Isa 37:36: 'the angel of the LORD put to death 185,000 in the Assyrian camp' — not a human army. 'His young warriors will be broken into forced labor' (venosav lamas yihyeh, and his young men will become for tribute/forced labor) = the survivors enslaved.</p>",
    "9": "<p>'His stronghold will crumble in terror, and his commanders will be terrified at the signal standard, declares the LORD, whose fire is in Zion and whose furnace is in Jerusalem' — the final defeat of Assyria's command structure: 'vesilao mippachad ya'avor, his rock/stronghold will pass away in terror' (sela = rock, the same word as YHWH the Rock in 26:4 — Assyria's rock-stronghold crumbles in terror before YHWH the Rock). 'And his commanders will be terrified at the signal-standard' (vemissa'o mechita, from the signal he will be shattered) — the nessa/banner that Israel raises for YHWH's battle (11:10, 12; 49:22; 62:10) is the very thing that destroys Assyria's commanders. 'Whose fire is in Zion and whose furnace is in Jerusalem' (asher uro beTsiyon vetannuro biYerushalayim, whose fire is in Zion and his furnace in Jerusalem) = Jerusalem itself is the site of the divine fire (cf. 33:14: 'who of us can dwell with the consuming fire?' = YHWH enthroned in Zion).</p>"
  },
  "32": {
    "1": "<p>'See — a king will reign in righteousness, and his rulers will govern with justice' — the messianic governance oracle: 'hineh lesedeq yimlokh-melek, behold a king will reign in righteousness.' The sedeq (righteousness/justice) as the defining attribute of the ideal king echoes 11:4-5: 'with righteousness he will judge the needy... righteousness will be his belt.' The contrast with the current kings whose policy is oppression (30:12) and the Egypt alliance. 'And his rulers will govern with justice' (vesarim lemishpat yashoru, and princes for justice will govern) — the leadership team (sarim = princes/officials) also characterized by mishpat (justice). This pairs with 28:6 (where YHWH gives 'a spirit of justice to those who sit in judgment'): the messianic era restores just governance at every level. Historically applied to Hezekiah's reform; eschatologically to the Davidic Messiah.</p>",
    "2": "<p>'Each leader will be like a hiding place from the wind, a shelter from the storm — like streams of water in a dry land, like the shade of a great rock in a parched and weary ground' — the four shelter-images for ideal leadership. 'Vehayah ha'ish keseter ruach, and the man will be like a hiding place from the wind' (seter = a covered place, a hiding place, cf. Ps 32:7: 'you are my hiding place'). 'And a shelter from the storm' (vesekher mizarem, a refuge from the rain/storm). 'Like streams of water in a dry place' (kefalge mayim betsayyon, like streams/channels of water in a dry land = the wadi-water in the Negev wilderness after rain). 'Like the shade of a great rock in a weary land' (ketsel sela kaved be'erets ayefah, like the shade of a heavy/great rock in a weary land) — four protective functions against four natural threats: wind, storm, thirst, scorching heat. The messianic leader as creation-shelter against creation's threats.</p>",
    "3": "<p>'Then the eyes of those who see will no longer be closed, and the ears of those who hear will be attentive' — the reversal of the blindness-deafness of 6:9-10 and 29:9-12: 'velo tish'einah einei ro'im, and the eyes of those who see will not be dull/glazed.' Tish'einah (from sha'ah = to be smeared over, to be dull/glazed) = the physical-spiritual unseeing of those under the spirit of deep sleep (29:10). 'And the ears of those who hear will be attentive' (ve'ozne shome'im tiqshavna, and the ears of those who hear will be alert) — tiqshavna from qashav = to pay close attention, to be attentive (the same verb as Ps 17:1: 'hear my righteous plea; listen/be attentive to my cry'). The complete reversal: those whose eyes saw nothing and ears heard nothing in the era of judgment now see and hear fully in the messianic era.</p>",
    "4": "<p>'The heart of the impulsive will understand and know, and the tongue of those who stumbled over words will speak with clarity' — the cognitive-communicative restoration: 'velev nahum yavvein lada'at, and the heart of the rash/impulsive will understand to know.' The nahumm (rash/hasty, from nahm = to hasten recklessly) = those whose decision-making was impulsive and ill-considered (the opposite of the wise counsel of 28:29). 'Will understand' (yavvein = the same root as beinah, understanding) 'to know' (lada'at) = the full cognitive restoration. 'And the tongue of those who stumbled over words will speak with clarity' (velashon ilgim temalel mahir, and the tongue of the stammerers will speak quickly/clearly). The ilgim (stammerers/those who speak poorly = the foreign-tongue invaders of 28:11; also perhaps those unable to speak clearly in prophetic court) now speak mahir (quickly, fluently, clearly). The messianic era heals communication.</p>",
    "5": "<p>'No longer will the fool be called noble, nor the miser praised as generous' — the reversal of false social labels: 'lo-yiqare od lenavel nadiv, no longer will the fool be called noble.' The naval (fool = the morally obtuse, the one who denies God's claim on his life, Ps 14:1: 'the fool says in his heart there is no God'; Prov 17:7: 'lofty speech is not fitting for a fool'; 1 Sam 25:25: Nabal/naval as a name-that-fits) called nadiv (noble = the generous, open-handed, spiritually exalted person). In the current age, the fool gets social credit for noble status. 'Nor will the miser be praised as generous' (velekilay lo ye'amer shoa, and the miser will not be said to be generous/bountiful) — shoa (bountiful/generous/noble = the prosperous person who gives freely) applied to the kilay (the knavish/fraudulent miser). The false labeling of the current social order corrected.</p>",
    "6": "<p>'For the fool speaks foolishness, and his heart devises wickedness — practicing godlessness and speaking distortion about the LORD, leaving the hungry without food and cutting off drink from the thirsty' — the definition of the naval by his speech and deeds: 'ki naval nevulah yedabber velibbo ya'aseh-aven, for the fool speaks foolishness and his heart does/makes iniquity.' The naval's two domains: speech (nevulah = vileness/disgrace, from the same root as naval) and heart-deeds (aven = iniquity/trouble). 'Practicing godlessness' (la'asot chanef, to do profaneness/godlessness — chanef = the polluted/profane person who violates sacred boundaries). 'And speaking distortion about YHWH' (vedabber el-YHWH tatuf, speaking concerning YHWH distortion/error) = false theology that misrepresents YHWH's character. The social consequences: 'to leave the hungry without food' (lehariq nefesh ra'ev) and 'cut off drink from the thirsty' (umashqeh tsame yachser) — active deprivation of the vulnerable.</p>",
    "7": "<p>'The miser's schemes are all evil; he devises wicked plans to ruin the poor with false words, even when the needy speak the truth' — the keli (miser/knave, the fraudulent dealer) analyzed: 'ukheli kelav re'im, and the tools/instruments of the knave are evil.' Keli (vessel/instrument, but also 'the knave himself') = the miser's whole apparatus of scheming. 'He devises wicked plans' (hu zimot yiyetsov leshachet anavim, he devises schemes to destroy the humble/poor) — the specific target: the anavim (the meek/poor, as in 29:19). 'With false words' (bishfat-shaqer, with words of deception/falsehood). 'Even when the needy speak the truth' (ve'im-dabbur evyon mishpat, and when the poor man speaks justice/right). The miser's wickedness is in perverting justice even against those who speak the truth — the most blatant corruption of the gate-court (21:28-21's legal snares).</p>",
    "8": "<p>'But the noble person plans noble things, and by noble deeds he stands firm' — the positive counter-definition of the nadiv (noble/generous): 'venediv nadivot ya'ats, and the noble person plans noble things.' The nadiv (the free, open-handed, generous spirit) makes nadivot (noble plans/generous plans). 'And on noble deeds he stands firm' (ve'hu al-nadivot yaqum, and he on noble deeds will stand firm). The standing-firm (yaqum = will rise/stand) of the noble: the nadiv's nobility is self-sustaining — the generous character that plans generously produces the stability that allows continued generosity. Contrast the schemes of the kali (v.7) that destroy — the nadiv's plans build. This is the social order of the messianic king's realm (v.1): justice produces the stable community where the noble can thrive and the poor are protected.</p>",
    "9": "<p>'Rise up, you women who are at ease; hear my voice. Give attention to what I say, you complacent daughters' — the women's oracle paralleling the men's: 'nashim sha'ananot qumnah, women who are at ease, rise up; shime'u qoli, hear my voice.' The sha'ananot (women at ease/secure = complacent, comfortable) are addressed in prophetic counter-intuition: when society assumes safety, the prophet announces judgment. The parallel address: 'banot betachot, complacent daughters' (batachot = confident, secure, from batach = to trust, the misplaced trust that pervades chs. 28-31). This oracle echoes Amos 4:1-3 ('hear this word, you cows of Bashan on Mount Samaria — you women who oppress the poor and crush the needy and say to your husbands, Bring us some drinks!') where women are addressed as the barometers of societal complacency.</p>",
    "10": "<p>'In little more than a year you complacent women will tremble, for the grape harvest will fail and the gathering will not come' — the harvest-failure oracle: 'yamim al-shanah tir'adna, days and a year you will tremble' (tir'adna = you (feminine plural) will be shuddering). 'Days and a year' = within a year and a few days (the indefinite 'soon but not immediately'). 'For the grape harvest will fail' (ki kalah batsiyr, for the vintage is finished/done = no vintage this year). 'And the gathering will not come' (ve'asaf lo yavo, and the fruit-gathering will not arrive). The grape harvest (batsir) was the great autumn celebration that marked the end of the agricultural year — its failure was an economic and social catastrophe. The complacent women who assumed continued prosperity will tremble when the harvest they counted on does not materialize.</p>",
    "11": "<p>'Tremble, you women who are at ease; shudder, you who feel secure! Strip off your clothes, bare your body, and tie sackcloth around your waist' — the mourning ritual commands: 'rig'u sha'ananot, tremble/shudder, you at-ease ones' (rig'u from ragaz = to tremble/be disturbed). 'Vachargazu batahot, and shudder, you secure ones.' The commands intensify: from trembling to undressing for mourning rites. 'Strip off your clothes' (peshitah veoru, strip and make yourselves naked) = the stripping of mourning, the removal of status garments (cf. 2 Sam 3:31: 'tear your clothes and put on sackcloth and walk in mourning before Abner'). 'Tie sackcloth around your waist' (vachagoru al-chalatsayim, and gird on the hips) — sackcloth (the rough goat-hair cloth of mourning, Gen 37:34; 2 Sam 3:31; Jon 3:5-8) around the waist = the complete reversal from festival dress to mourning dress.</p>",
    "12": "<p>'Beat your breasts in mourning for the pleasant fields and the fruitful vines' — the breast-beating mourning gesture: 'al-shadayim sof'dim, over the breasts beat in mourning' (sof'dim = beating the chest in grief, from safad = to wail/beat in mourning). The object of mourning: 'al-sadot chemad, over the pleasant/desirable fields' and 'al-gefen poriyah, over the fruitful vine.' The fields (sadot) and vines (gefen) are the two primary agricultural products of the land — their loss is the loss of the covenant blessing (Deut 8:8: 'a land with wheat and barley, vines and fig trees'). The women mourn over the agricultural landscape as if over the dead — because the failed harvest is as devastating as death for the covenant community's sustenance.</p>",
    "13": "<p>'Thorns and briers will spring up on the soil of my people's land, on every house of celebration in the bustling city' — the covenant-curse vegetation: 'al-admat ammi, on the soil of my people' (admat ammi = the covenant land-of-my-people; adamah = the soil, the cultivated land given under covenant). 'Sha'amiyah kol-beit masos qiryah alitsah, thorns and briers will spring up — over every house of celebration, over the jubilant city.' The shamir vashayit (thorns and briers) = the judgment-vegetation of 5:6; 7:23-25; 9:18; 10:17; 27:4; 32:13 — the thorn-complex that signals the reversal of the cultivated covenant-land back to wilderness. The 'houses of celebration' (beit masos, houses of rejoicing = the places of the festival/banquet culture) abandoned, overgrown with thorns. The jubilant city silenced.</p>",
    "14": "<p>'For the palace will be abandoned, the busy city deserted; the citadel and the watchtower will serve as lairs for wild donkeys and grazing ground for flocks — forever' — the complete depopulation: 'ki-armun nuttash, for the palace will be abandoned' (nuttash = forsaken/abandoned, the technical term for covenant-abandonment). 'Qiryah hamonah uzuvah, the crowded/bustling city forsaken.' The two markers of civilization (palace = royal governance; crowded city = commercial social life) both abandoned. 'The citadel and the watchtower will become caves/lairs forever' (ofel vavachan hayah mearot, the hill-citadel and watchtower will be for dens) — 'for wild donkeys' (ad-olam, to the age) = the permanent de-civilization of the site. 'Grazing ground for flocks' (mire'eh pere-chamor, grazing for the wild donkey) — the domestic city becomes wild pasture. The same imagery as 13:20-22 (Babylon) and 34:13-15 (Edom).</p>",
    "15": "<p>'Until the Spirit is poured upon us from on high, and the wilderness becomes a fruitful orchard, and what is fruitful orchard is counted as forest' — the Spirit-outpouring as the reversal-agent: 'ad-yiare aleinu ruach mimmmarom, until the Spirit is poured/laid upon us from above.' The ruach (Spirit = the divine wind/breath/Spirit of Gen 1:2 that hovered over the primordial chaos) 'poured from above' = the vertical descent of divine power. The agricultural reversal follows immediately: 'vehayah midbar lakarmel, and the wilderness will become a fruitful orchard.' Midbar (wilderness/desert) → karmel (fruitful garden-land). 'And the karmel will be counted as a forest' (vehakarmel laya'ar yekhashev, and the orchard will be reckoned as a forest) — the fruitful orchard becomes so abundantly productive it registers as a wild forest. Joel 2:28-29 expands this Spirit-outpouring; Peter cites Joel at Pentecost (Acts 2:17): 'In the last days, God says, I will pour out my Spirit on all people.'</p>",
    "16": "<p>'Then justice will dwell in the wilderness, and righteousness remain in the fruitful orchard' — the ecological transformation producing social transformation: 'veshakhan bamidbar mishpat, and justice will dwell in the wilderness.' The midbar (wilderness) that was previously the domain of chaos and danger (the Negev through which Judean ambassadors traveled to Egypt at great risk, 30:6) now becomes the habitat of mishpat (justice). 'And righteousness remain in the fruitful orchard' (utsedaqah bakarmel teshev, and righteousness will sit in the orchard). The double: justice in the wild place (wilderness) and righteousness in the cultivated place (orchard). The Spirit's transformation reaches both the uncultivated and cultivated domains of the land.</p>",
    "17": "<p>'The fruit of righteousness will be peace, and the result of righteousness will be quietness and confident security forever' — the righteousness → peace → security chain: 'vehayah ma'aseh hatsedaqah shalom, and the product of righteousness will be peace.' The three-stage sequence: tsedaqah (righteousness = the right ordering of covenant relationships) produces shalom (peace = the comprehensive well-being of the whole community). And the 'service/result of righteousness' (avoda hatsedaqah) = 'quietness and security forever' (hashqet uvetach ad-olam, quietness and confidence/security to the age). The betach (security = the same root as the misplaced trust of the Egypt-alliance: in 30:15 'in quietness and trust shall be your strength' — now realized in the Spirit-era). When righteousness is the foundation, the quietness of 30:15 is finally available.</p>",
    "18": "<p>'My people will dwell in a peaceful home, in secure dwellings, and in undisturbed resting places' — the threefold dwelling-security: 'veyashav ammi binaveh shalom, and my people will dwell in a home of peace.' Naveh shalom (home of peace = the peaceful pasture of a flock, the settled dwelling of a covenant community at rest). 'In secure dwellings' (umishshenot mibtachim, and in secure habitations — mibtachim from batach = the trustworthy/confident, the dwelling that can be relied upon). 'And in quiet resting places' (uvmenuchot sha'ananot, and in quiet resting places — menucha = the rest of Ps 23:2: 'he leads me beside quiet waters... he makes me lie down in green pastures'). The triple description of the Spirit-era community: peaceful home, secure dwelling, quiet rest — the complete reversal of the fear, siege, and exile that characterized the Assyrian crisis.</p>",
    "19": "<p>'Even when hail comes crashing through the forest and the city is utterly humbled and leveled' — the eschatological stability even in cosmic disturbance: 'uvarad beredet hayya'ar, and hail in the falling of the forest.' Even when the hailstorm of judgment crashes through the forest (the military image: the battle of 30:30's hailstones destroying the Assyrian force), and 'the city is utterly humbled' (ubeshoflah tishpal ha'ir, and in the lowering the city will be humbled). The repeated shofal (brought low): both the forest and the city are humbled. Yet the covenant community's 'peaceful home, secure dwelling, quiet rest' (v.18) endure through the external turmoil. The surrounding destruction does not destabilize the Spirit-filled community's rest.</p>",
    "20": "<p>'Blessed are you who sow beside every stream, who let your oxen and donkeys range freely' — the beatitude of the Spirit-era farmer: 'ashreikhem zor'e al-kol-mayim, blessed are you who sow beside all waters.' The ashre (blessed = the beatitude formula of Ps 1:1; Matt 5:3-12) applied to the farmer. 'Beside all waters' (al-kol-mayim = beside every body of water) = the unlimited water access of the Spirit-era (streams on every mountain in 30:25; the poured-out Spirit of 32:15). 'Who let your ox and donkey range freely' (meshalche regel hashhor vehacharor, who send freely the foot of the ox and the donkey) — the working animals roam without restriction, finding abundant pasture everywhere (30:23-24's 'spacious pastures' and 'salted fodder'). The Spirit-era blessing extends to the animals who labor for the community.</p>"
  }
}

def main():
    c = load_comm('mkt-context', 'isaiah')
    merge_comm(c, ISA_CONTEXT)
    save_comm('mkt-context', 'isaiah', c)
    total_v = sum(len(vv) for vv in c.values())
    print(f'Isaiah context: {len(c)} chapters, {total_v} verses')

if __name__ == '__main__':
    main()
